def safe_divide(a, b):
    try:
        return a / b
    except ZeroDivisionError:
        return "Oops! You can't divide by zero. 🙂"

print(safe_divide(10, 2))
print(safe_divide(10, 0))

def to_number(text):
    try:
        return int(text)
    except ValueError:
        return "That doesn't look like a whole number. 🤔"

print(to_number("42"))
print(to_number("cat"))

ages = {"Sam": 9, "Mia": 11}

def look_up(name):
    try:
        age = ages[name]
    except KeyError:
        print(name + " is not in our list. 🔍")
    else:
        print(name + " is " + str(age) + " years old.")
    finally:
        print("(done looking)")

look_up("Mia")
look_up("Alex")

def set_age(age):
    if age < 0:
        raise ValueError("Age can't be negative!")
    return "Age set to " + str(age)

try:
    print(set_age(-5))
except ValueError as oops:
    print("Caught it:", oops)

